import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import { loadService } from "../services";
import "../styles/CreateLoad.css";

const ALL_CITIES = [
  "Aruppukottai",
  "Kariapatti",
  "Tirunelveli",
  "Nagercoil",
  "Kanyakumari",
  "Madurai",
  "Theni",
  "Dindigul",
  "Coimbatore",
  "Salem",
  "Erode",
  "Chennai",
  "Bangalore",
  "Hyderabad",
  "Mumbai",
  "Delhi",
  "Pune",
  "Kolkata",
  "Jaipur",
  "Lucknow",
  "Chandigarh",
  "Indore",
  "Visakhapatnam",
  "Pimpri-Chinchwad",
  "Ahmedabad",
  "Surat",
  "Vadodara",
  "Rajkot",
  "Kota",
  "Udaipur",
  "Jodhpur",
  "Guwahati",
  "Patna",
  "Ranchi",
  "Kolhapur",
  "Aurangabad",
  "Nashik",
  "Indore",
  "Bhopal",
  "Jabalpur",
];

const CreateLoad = () => {
  const [formData, setFormData] = useState({
    title: "",
    description: "",
    pickupLocation: "",
    dropLocation: "",
    weight: "",
    price: "",
  });
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);
  const [pickupSuggestions, setPickupSuggestions] = useState([]);
  const [dropSuggestions, setDropSuggestions] = useState([]);
  const [showPickupDropdown, setShowPickupDropdown] = useState(false);
  const [showDropDropdown, setShowDropDropdown] = useState(false);
  const navigate = useNavigate();

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  const validateForm = () => {
    if (
      !formData.title ||
      !formData.pickupLocation ||
      !formData.dropLocation ||
      !formData.weight ||
      !formData.price
    ) {
      setError("All required fields must be filled");
      return false;
    }
    if (formData.weight <= 0 || formData.price <= 0) {
      setError("Weight and price must be greater than 0");
      return false;
    }
    return true;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");

    if (!validateForm()) return;

    setLoading(true);
    try {
      await loadService.createLoad(formData);
      navigate("/loads");
    } catch (err) {
      setError(err.response?.data?.message || "Failed to create load");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="create-load-container">
      <div className="create-load-box">
        <h2>Create New Load</h2>
        {error && <div className="error-message">{error}</div>}
        <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label>Title *</label>
            <input
              type="text"
              name="title"
              value={formData.title}
              onChange={handleChange}
              placeholder="Load title"
            />
          </div>
          <div className="form-group">
            <label>Description</label>
            <textarea
              name="description"
              value={formData.description}
              onChange={handleChange}
              placeholder="Load description"
              rows="4"
            />
          </div>
          <div className="form-row">
            <div className="form-group">
              <label>Pickup Location *</label>
              <select
                name="pickupLocation"
                value={formData.pickupLocation}
                onChange={handleChange}
              >
                {CITIES.map((city) => (
                  <option
                    key={city}
                    value={city === "Select Pickup City" ? "" : city}
                  >
                    {city}
                  </option>
                ))}
              </select>
            </div>
            <div className="form-group">
              <label>Drop Location *</label>
              <select
                name="dropLocation"
                value={formData.dropLocation}
                onChange={handleChange}
              >
                <option value="">Select Drop City</option>
                {CITIES.slice(1).map((city) => (
                  <option key={city} value={city}>
                    {city}
                  </option>
                ))}
              </select>
            </div>
          </div>
          <div className="form-row">
            <div className="form-group">
              <label>Weight (kg) *</label>
              <input
                type="number"
                name="weight"
                value={formData.weight}
                onChange={handleChange}
                placeholder="Weight"
                step="0.1"
              />
            </div>
            <div className="form-group">
              <label>Price ($) *</label>
              <input
                type="number"
                name="price"
                value={formData.price}
                onChange={handleChange}
                placeholder="Price"
                step="0.01"
              />
            </div>
          </div>
          <button type="submit" disabled={loading} className="btn-primary">
            {loading ? "Creating..." : "Create Load"}
          </button>
        </form>
      </div>
    </div>
  );
};

export default CreateLoad;
